// Montar datas para verificação no Google Calendar
const d = $input.first().json.body || $input.first().json;
const ag = d.agendamento;

if (!ag || !ag.data || !ag.hora) {
  return [{ json: { erro: 'Dados de agendamento incompletos', ...d } }];
}

// Construir ISO datetime (Brasília UTC-3)
const [year, month, day] = ag.data.split('-').map(Number);
const [hour, minute] = ag.hora.split(':').map(Number);

// Início do evento em UTC (Brasília = UTC-3)
const startUTC = new Date(Date.UTC(year, month - 1, day, hour + 3, minute));
const endUTC = new Date(startUTC.getTime() + 60 * 60 * 1000); // +1 hora

const startISO = startUTC.toISOString().replace('.000Z', '-03:00').replace('Z', '');
const endISO = endUTC.toISOString().replace('.000Z', '-03:00').replace('Z', '');

// Para buscar eventos do dia (range de 24h)
const dayStartISO = new Date(Date.UTC(year, month - 1, day, 3, 0)).toISOString();
const dayEndISO = new Date(Date.UTC(year, month - 1, day, 27, 0)).toISOString();

return [{
  json: {
    ...d,
    startDateTime: startISO,
    endDateTime: endISO,
    dayStartISO,
    dayEndISO,
    dataFormatada: `${String(day).padStart(2,'0')}/${String(month).padStart(2,'0')}/${year}`,
    horaFormatada: `${String(hour).padStart(2,'0')}:${String(minute).padStart(2,'0')}`
  }
}];

// Verificar se o horário está disponível
const calResp = $input.first().json;
const conv = $('Preparar Datas').first().json;

const existingEvents = calResp.items || [];
const requestedStart = new Date(conv.startDateTime).getTime();
const requestedEnd = new Date(conv.endDateTime).getTime();

// Verificar conflito com eventos existentes
const temConflito = existingEvents.some(ev => {
  const evStart = new Date(ev.start?.dateTime || ev.start?.date).getTime();
  const evEnd = new Date(ev.end?.dateTime || ev.end?.date).getTime();
  return evStart < requestedEnd && evEnd > requestedStart;
});

return [{
  json: {
    ...conv,
    horarioDisponivel: !temConflito,
    eventosExistentes: existingEvents.length
  }
}];

// Montar mensagem de confirmação com link do Meet
const eventData = $input.first().json;
const conv = $('Verificar Disponibilidade').first().json;

const meetLink = eventData.conferenceData?.entryPoints?.find(ep => ep.entryPointType === 'video')?.uri || '';
const ag = conv.agendamento;

const mensagem = `✅ Agendamento confirmado com sucesso!

📅 Data: ${conv.dataFormatada}
⏰ Horário: ${conv.horaFormatada}
👤 Nome: ${ag.nome}
📧 E-mail: ${ag.email}
⚖️ Assunto: ${ag.descricao}

📹 Modalidade: Google Meet
${meetLink ? `🔗 Link: ${meetLink}` : '🔗 O link será enviado por e-mail em breve.'}

Se precisar alterar ou cancelar, é só me avisar. 😊`;

return [{
  json: {
    ...conv,
    meetLink,
    eventoId: eventData.id,
    mensagemConfirmacao: mensagem
  }
}];

// Horário indisponível — oferecer alternativas
const d = $input.first().json;
const ag = d.agendamento;

const mensagem = `Olá, ${ag.nome}! 😊

Infelizmente o horário escolhido (${d.dataFormatada} às ${d.horaFormatada}) já está ocupado.

Posso sugerir algumas alternativas próximas:

📅 Horários disponíveis:
- Segunda-feira: 09h | 11h | 14h | 16h
- Terça-feira: 10h | 13h | 15h | 17h
- Quarta-feira: 09h | 12h | 14h | 16h
- Quinta-feira: 09h | 11h | 15h | 17h
- Sexta-feira: 10h | 12h | 14h | 16h

Qual opção é melhor para você?`;

return [{
  json: {
    ...d,
    mensagemAlternativa: mensagem
  }
}];
